// ============================================================
// JSON OUTPUT PARSER
// KEY FIXES:
// 1. loop_count read from Max Retries Reached? node because
//    Agent nodes strip all fields except {output} from items.
// 2. initial_vulnerabilities stored in workflow static data
//    keyed by execution ID so it survives loop iterations.
// 3. Saved on FIRST visit (null check) and never overwritten.
// 4. False-positive Bandit findings on already-patched code
//    are filtered out to prevent infinite loops.
// 5. Loop convergence check: if no NEW vuln types appear on
//    re-scan, the Patcher has done its job — exit the loop.
// ============================================================

for (const item of items) {
  try {
    // --- STATIC DATA (survives across loop iterations) ---
    const staticData = $getWorkflowStaticData('global');
    const execId = ($execution && $execution.id)
      ? String($execution.id)
      : 'run_' + Date.now();
    if (!staticData.runs) staticData.runs = {};
    if (!staticData.runs[execId]) {
      staticData.runs[execId] = { initial_vulnerabilities: null };
    }

    // --- PARSE AUDITOR OUTPUT ---
    const rawOutput = item.json.output;
    let parsedData = {};

    if (typeof rawOutput === 'object' && rawOutput !== null) {
      parsedData = rawOutput;
      Object.assign(item.json, parsedData);
    } else if (typeof rawOutput === 'string') {
      let s = rawOutput
        .replace(/^```json\s*/g, '')
        .replace(/\s*```$/g, '')
        .replace(/^```\s*/g, '')
        .trim();

      try {
        parsedData = JSON.parse(s);
        Object.assign(item.json, parsedData);
      } catch (e) {
        item.json.parse_warning = 'JSON parse failed, attempting regex salvage';
        const m = s.match(/"vulnerabilities"\s*:\s*\[([\s\S]*?)\]/);
        if (m) {
          try { item.json.vulnerabilities = JSON.parse('[' + m[1] + ']'); }
          catch (e2) { item.json.vulnerabilities = []; }
        }
      }
    }

    // --- NORMALISE VULNERABILITIES ---
    if (!item.json.vulnerabilities) item.json.vulnerabilities = [];
    item.json.vulnerabilities = item.json.vulnerabilities.map(v => ({
      line_number: v.line_number || v.line || 0,
      type: v.type || 'Security Issue',
      severity: (v.severity || 'MEDIUM').toUpperCase(),
      issue_text: v.issue_text || v.description || (v.type + ' detected'),
      original_code: v.original_code || '',
      fixed_code: v.fixed_code || '',
      fix_recommendation: v.fix_recommendation || ''
    }));

    // --- FILTER FALSE POSITIVES on already-patched code ---
    const falsePositivePatterns = [
      /subprocess\.run\(\[.*\],\s*shell\s*=\s*False/,
      /subprocess\.run\(\[.*\],\s*check\s*=\s*True/,
    ];
    const ignoredTypes = ['import_subprocess'];
    item.json.vulnerabilities = item.json.vulnerabilities.filter(v => {
      if (ignoredTypes.includes(v.type)) return false;
      const code = v.original_code || '';
      if (falsePositivePatterns.some(re => re.test(code))) return false;
      return true;
    });

    // --- DETERMINE has_issues ---
    item.json.has_issues = item.json.vulnerabilities.length > 0;

    // --- CURRENT CODE ---
    item.json.audited_code = $('Max Retries Reached?').first().json.code;
    if (!item.json.full_corrected_code) {
      item.json.full_corrected_code = item.json.audited_code;
    }

    // --- SAVE INITIAL VULNS ONCE (null guard prevents overwrite on re-runs) ---
    if (staticData.runs[execId].initial_vulnerabilities === null) {
      staticData.runs[execId].initial_vulnerabilities =
        JSON.parse(JSON.stringify(item.json.vulnerabilities));
    }

    // --- LOOP CONVERGENCE CHECK ---
    const loopCount = staticData.runs[execId].loop_count || 0;
    if (loopCount >= 1 && item.json.has_issues) {
      const currentTypes = new Set(item.json.vulnerabilities.map(v => v.type));
      const initialTypes = new Set(
        (staticData.runs[execId].initial_vulnerabilities || []).map(v => v.type)
      );
      const newTypes = [...currentTypes].filter(t => !initialTypes.has(t));
      if (newTypes.length === 0) {
        item.json.has_issues = false;
      }
    }

    // --- POPULATE SUMMARY METRICS ---
    const initialVulns = staticData.runs[execId].initial_vulnerabilities;
    item.json.number_of_vulnerabilities_fixed = initialVulns.length;
    const types = initialVulns.map(v => v.type || 'Unknown');
    item.json.types_of_vulnerabilities = [...new Set(types)];
    item.json.vulnerabilities_details = initialVulns.map(v => ({
      type: v.type || 'Unknown',
      original_line_number: v.line_number || 0
    }));

  } catch (error) {
    item.json.error = error.message;
    item.json.vulnerabilities = [];
    item.json.has_issues = false;
  }
}

return items;

